@app.route('/upload_resume', methods=['GET', 'POST'])
def upload_resume():
    if request.method == 'GET':
        # No frontend specified, no redirect or JSON required, just redirect to root per spec
        return redirect(url_for('root_redirect'))
    else:
        applicant_name = request.args.get('applicant_name', '')
        applicant_email = request.args.get('applicant_email', '')
        resume_file = request.args.get('resume_file', '')
        summary = request.args.getlist('summary')

        if not all([applicant_name, applicant_email, resume_file]):
            abort(400, 'Missing required fields')

        resumes = load_resumes()
        new_id = 1
        if resumes:
            try:
                new_id = max(int(r['resume_id']) for r in resumes) + 1
            except:
                new_id = len(resumes) + 1
        # Compose summary string if list given
        summary_str = ' '.join(summary) if summary else ''
        upload_date_str = datetime.now().strftime('%Y-%m-%d')
        new_resume = {
            'resume_id': str(new_id),
            'applicant_name': applicant_name,
            'applicant_email': applicant_email,
            'filename': resume_file,
            'upload_date': upload_date_str,
            'summary': summary_str
        }
        resumes.append(new_resume)
        save_data_file('resumes.txt', resumes, RESUME_FIELDS)
        return redirect(url_for('resume_management_page'))

