@app.route('/search', methods=['POST'])
def search_results_page():
    query = request.form.get('query', '')
    jobs = load_jobs()
    companies = load_companies()
    job_results = {}
    company_results = {}

    # Filter job_results where title or location or company name contains query string (case insensitive)
    for job in jobs:
        comp = next((c for c in companies if c['company_id'] == job['company_id']), None)
        if comp is None:
            continue
        if query.lower() in job['title'].lower() or query.lower() in job['location'].lower() or query.lower() in comp['company_name'].lower():
            try:
                title_val = int(job['title'])
            except:
                title_val = 0
            try:
                company_name_val = int(comp['company_name'])
            except:
                company_name_val = 0
            try:
                location_val = int(job['location'])
            except:
                location_val = 0
            job_results[job['job_id']] = {
                'job_id': job['job_id'],
                'title': title_val,
                'company_name': company_name_val,
                'location': location_val,
                'salary_min': job['salary_min'],
                'salary_max': job['salary_max']
            }
    # Filter company_results where company_name or industry contains query string
    for comp in companies:
        if query.lower() in comp['company_name'].lower() or query.lower() in comp['industry'].lower():
            try:
                company_name_val = int(comp['company_name'])
            except:
                company_name_val = 0
            try:
                industry_val = int(comp['industry'])
            except:
                industry_val = 0
            company_results[comp['company_id']] = {
                'company_id': comp['company_id'],
                'company_name': company_name_val,
                'industry': industry_val
            }

    try:
        query_val = int(query)
    except:
        query_val = 0

    return render_template('search_results.html', query=query_val, job_results=job_results, company_results=company_results)

